<?php
namespace App\Livewire\Forms; use Livewire\Form; class ObservationScheduleForm extends Form { public string $schedule_type='vital_signs'; public ?int $interval_minutes=60; public ?string $starts_at=null; public ?string $ends_at=null; public ?string $instructions=null; public function rules(): array { return ['schedule_type'=>['required'],'interval_minutes'=>['nullable','integer','min:1']]; } public function validationAttributes(): array { return ['schedule_type'=>'aina ya ratiba']; } public function normalize(): array { return $this->all(); } public function fillFromModel($m): void { $this->fill($m->only(array_keys($this->normalize()))); } public function resetForm(): void { $this->reset(); $this->schedule_type='vital_signs'; $this->interval_minutes=60; } }
